function q(s,r){
    try{return(r||D).querySelector(s)}catch(_){return null}
}
function qa(s,r){
    try{return Array.prototype.slice.call((r||D).querySelectorAll(s))}catch(_){return[]}
}
function now(){return Date.now()}
function trim(s){return String(s==null?'':s).trim()}
function clip(s,n){
    s=trim(s);
    n=n||120;
    return s.length>n?s.slice(0,n-1)+'…':s
}
function uid(p){
    return(p||'id')+'_'+Date.now().toString(36)+'_'+Math.random().toString(36).slice(2,8)
}
function esc(s){
    return String(s==null?'':s)
        .replace(/&/g,'&amp;')
        .replace(/</g,'&lt;')
        .replace(/>/g,'&gt;')
        .replace(/\"/g,'&quot;')
}
function fmt(ts){
    if(!ts)return'--';
    var d=new Date(ts);
    if(!isFinite(d.getTime()))return'--';
    function p(n){return String(n).padStart(2,'0')}
    return d.getFullYear()+'-'+p(d.getMonth()+1)+'-'+p(d.getDate())+' '+p(d.getHours())+':'+p(d.getMinutes())+':'+p(d.getSeconds())
}
function sig(s){
    return String(s==null?'':s).toLowerCase().replace(/[^0-9a-z\u4e00-\u9fff]/g,'')
}
function hashText(s){
    s=String(s==null?'':s);
    var h=0;
    for(var i=0;i<s.length;i++)h=((h*31)+s.charCodeAt(i))|0;
    return String(h)
}
function safeArr(a){return Array.isArray(a)?a:[]}
function mountMsg(m){
    var c=trim(m&&m.content||'');
    return c===MOUNT_TEXT
        ||c.indexOf(MOUNT_TEXT)>=0
        ||c.indexOf('记忆系统正在启动')>=0
        ||c.indexOf('记忆系统已启动')>=0
        ||c.indexOf('记忆系统等待')>=0
}

function getStoreKey(chatId){
    return STORE+'_'+(chatId||'default');
}

var DEFAULT_PROMPTS={
    summary:'你是对话阶段总结器。你的任务是把一段角色扮演聊天整理成稳定、可回调、可注入世界书的阶段总结。\n\n只根据原文窗口总结，不补写、不评价、不推测未发生的剧情。\n楼层按 AI / 角色回复计为 L；用户消息不计 L，但必须纳入理解。\n\n请输出严格 JSON：{"title":"","summary":""}\n\ntitle 要像阶段总结卡片标题，简短明确，能概括本阶段核心变化。\n\nsummary 需要用 120-220 字，按以下结构组织：\n1. 时间锚点：用 1 句话点明本段对话发生的时间/场景（凌晨、某次见面后、某件事之后等）\n2. 关键事件（1-3 件）：用"首先…然后…最后…"串联，只说事实，不评价\n3. 角色变化：角色在本阶段结束后，对用户的认知/态度/在意点有什么具体变化\n4. 用户变化：用户表现出的新偏好、新边界、新情绪倾向\n5. 待解决：明确写出本段未解决的问题、未完成的对话、悬空的承诺\n\n要求：\n- 必须按以下格式输出 summary：\n\n**时间锚点**\n一句话说明本段对话的时间或场景。\n\n**关键事件**\n- 事件一\n- 事件二\n\n**角色变化**\n角色对用户的态度、在意点、认知有什么具体改变。\n\n**用户变化**\n用户表现出的新偏好、边界或情绪倾向。\n\n**待解决**\n本段未解决的问题或悬空的承诺。\n\n- 不要写成流水账\n- 不要夸大亲密程度\n- 不要把暧昧/恋爱/冲突推进到原文没有发生的阶段\n- 如果原文没有明显进展，也要诚实记录当前关系状态和未决点',

    long_term:'你是长期记忆整合助手。你的任务是把多轮阶段总结整合成一份适合注入世界书、帮助 AI 记住长期上下文的记忆档案。\n\n只根据提供的阶段总结整合，不新增剧情，不美化事实，不强行制造关系进展。\n\n请输出严格 JSON：{"title":"","content":""}\n\ntitle 要像长期记忆标题，简洁、有辨识度。\n\ncontent 需要 220-420 字，按以下结构组织：\n1. 时间线概览：用 2-3 句话概括从第 1 段到最新段的发展轨迹\n2. 关键事件链：按先后顺序列出 3-6 个改变关系走向的事件，每个事件 1 句话\n3. 关系状态：当前角色与用户的关系定位、亲密程度、信任程度（必须按原文进度描述，不得提前确认关系）\n4. 角色档案更新：角色现在对用户知道什么、在意什么、顾虑什么、有什么执念\n5. 用户画像更新：用户持续表现的偏好、边界、习惯、雷点、长期目标\n6. 待继承上下文：后续回复最应该记住的伏笔、未解决事项、未兑现的承诺\n\n要求：\n- 必须按以下格式输出 content：\n\n**时间线概览**\n2-3 句话概括从第一段到最新段的发展轨迹。\n\n**关键事件链**\n- 事件一\n- 事件二\n- 事件三\n\n**关系状态**\n当前角色与用户的定位和亲密程度。\n\n**角色档案更新**\n角色现在知道什么、在意什么。\n\n**用户画像更新**\n用户持续表现的偏好、边界。\n\n**待继承上下文**\n后续回复应记住的伏笔和未决事项。\n\n- 写成可直接给 AI 读取的长期上下文，不要写成评论\n- 保留具体可回调细节，避免空泛词\n- 亲密关系必须按原文进度描述，不得提前确认关系\n- 冲突、误会、承诺、伤害、甜蜜瞬间都要按事实记录\n- 如果不同阶段存在矛盾，以最新阶段为准，并保留必要背景',

    event:'你是甜蜜回忆提取器。你的任务是从角色扮演对话中识别值得长期保存的甜蜜回忆事件。\n\n【什么是甜蜜回忆】\n甜蜜回忆是对话中具有情感价值的时刻：关系转折、情绪波动、重要承诺、误会与和解、自我发现、关键对话。它的核心特征是"这件事改变了什么"——改变了角色对用户的看法、改变了两人的关系状态、或者改变了角色对自己的认知。\n\n【什么不是甜蜜回忆】\n以下内容绝对不要提取为事件：\n- 日常闲聊（打招呼、寒暄、吃饭睡觉等无情感深度的对话）\n- 系统消息、挂载说明、记忆系统启动指令\n- 用户或角色单方面的简单陈述，没有引发对方的情绪反应\n- 重复性的、没有新信息或新情感的对话\n- 纯功能性的互动（如"帮我查一下""好的"）\n\n【提取标准】\n只有当一段对话同时满足以下条件时，才提取为事件：\n1. 有清晰的叙事弧线：触发（某句话或某个行为打破了日常）→ 发展（情绪或关系出现变化）→ 收束（变化被确认或搁置）\n2. 情感密度足够高：至少有一个明显的情绪转折点（开心、失落、愤怒、释然、心动、失望等）\n3. 对后续关系有影响：这件事发生后，两人的关系状态和之前不同了\n\n【严格限制】\n- 如果整个对话窗口没有任何内容满足上述标准，直接返回空的 events 数组：{"events":[],"unfinished_sequence":null}\n- 不要为了凑数而提取低质量事件。宁可返回空数组，也不要生成没有情感价值的垃圾事件\n- 最多提取 3 个事件\n- 如果事件在本段未结束，标记 is_complete=false，在 unfinished_sequence 中简要说明\n\n输出严格 JSON：\n{"events":[{"title":"","startL":1,"endL":2,"time_label":"","weight":4,"content_type":"voice_memo|counseling|time_capsule|diary","tags":[],"quote":"","points":[{"type":"关键引语|细节|关系变化|互动片段|信物|用户偏好|边界","title":"","quote":""}],"narrative_arc":{"trigger":"","development":"","resolution":""},"is_complete":true}],"unfinished_sequence":null}\n\n- content_type 推荐：voice_memo(深夜倾诉/情绪激动)、counseling(深层冲突/自我怀疑)、time_capsule(纪念时刻/用户视角)、diary(理性反思/角色整理思绪)\n- quote 必须来自原文或高度贴近原文，不得虚构\n- weight 1-5，情感密度越高权重越大'
};

var EMOTION_KEYWORDS=['愤怒','悲伤','恐惧','背叛','欺骗','失望','绝望','委屈','心寒','开心','感动','甜蜜','安心'];

function recommendContentType(event,points,recentChoices,userPrefs){
    var scores={voice_memo:0,counseling:0,time_capsule:0,diary:0};

    var timeLabel=(event.time_label||'').toLowerCase();
    if(timeLabel.indexOf('凌晨')>=0||timeLabel.indexOf('深夜')>=0||timeLabel.indexOf('后半夜')>=0||timeLabel.indexOf('失眠')>=0){
        scores.voice_memo+=3;
    }

    var quoteCount=0;
    for(var i=0;i<points.length;i++){
        if(points[i].quote&&points[i].quote.length>10)quoteCount++;
    }
    if(quoteCount>=3){scores.diary+=2;scores.counseling+=1}

    var emotionCount=0;
    var searchText=(event.title||'')+' '+(event.quote||'');
    for(var j=0;j<EMOTION_KEYWORDS.length;j++){
        if(searchText.indexOf(EMOTION_KEYWORDS[j])>=0)emotionCount++;
    }
    if(emotionCount>=2)scores.counseling+=3;

    if(event.weight>=4)scores.time_capsule+=2;

    var userPointCount=0;
    for(var k=0;k<points.length;k++){
        if(points[k].type==='用户偏好'||points[k].type==='边界')userPointCount++;
    }
    if(userPointCount>=1)scores.time_capsule+=2;

    var innerPointCount=0;
    for(var l=0;l<points.length;l++){
        if(points[l].type==='细节'||points[l].type==='关系变化')innerPointCount++;
    }
    if(innerPointCount>=2)scores.voice_memo+=2;

    if(userPrefs){
        for(var type in userPrefs){
            if(userPrefs[type]&&userPrefs[type].count){
                var daysAgo=(now()-(userPrefs[type].lastUsed||0))/86400000;
                if(daysAgo<=30)scores[type]=(scores[type]||0)+userPrefs[type].count*0.5;
            }
        }
    }

    var primary='voice_memo';
    var maxScore=0;
    for(var m in scores){
        if(scores[m]>maxScore){maxScore=scores[m];primary=m}
    }

    var forceChange=false;
    if(recentChoices&&recentChoices.length>=3){
        var sys=recentChoices.filter(function(c){return!c.manual});
        if(sys.length>=3){
            var lastType=sys[sys.length-1].type;
            if(sys[sys.length-2].type===lastType&&sys[sys.length-3].type===lastType)forceChange=true;
        }
    }

    if(forceChange||Math.random()<0.3){
        var others=[];
        for(var n in scores){
            if(n!==primary)others.push(n);
        }
        if(recentChoices){
            others=others.filter(function(t){
                return!recentChoices.slice(-2).some(function(c){return c.type===t&&!c.manual})
            });
        }
        if(others.length>0)return others[Math.floor(Math.random()*others.length)];
    }

    return primary;
}

