function normalize(s){
    var d=defState();
    if(!s||typeof s!=='object')s=d;

    s.schema_version='3.3';
    s.started=!!s.started;
    s.baselineL=Number(s.baselineL||s.baselineA||0)||0;
    s.processedL=Number(s.processedL||s.processedA||0)||0;
    s.lastSeenAssistantId=String(s.lastSeenAssistantId||'');
    s.lastSeenMessageId=String(s.lastSeenMessageId||'');
    s.boundChatId=String(s.boundChatId||'');

    s.settings=Object.assign({},d.settings,s.settings||{});
    s.settings.interval=Math.max(8,Math.min(100,Number(s.settings.interval)||24));
    s.settings.long_term_rounds=Math.max(2,Math.min(10,Number(s.settings.long_term_rounds)||4));
    s.settings.auto_scan=false;
    s.settings.api_model=trim(s.settings.api_model)||'gpt-4o-mini';
    s.settings.prompts=Object.assign({},d.settings.prompts,s.settings.prompts||{});

    if(!trim(s.settings.prompts.summary))s.settings.prompts.summary=DEFAULT_PROMPTS.summary;
    if(!trim(s.settings.prompts.long_term))s.settings.prompts.long_term=DEFAULT_PROMPTS.long_term;
    if(!trim(s.settings.prompts.event))s.settings.prompts.event=DEFAULT_PROMPTS.event;

    ['summaries','long_term','events','points','milestones','logs'].forEach(function(k){
        if(!Array.isArray(s[k]))s[k]=[]
    });

    s.ui=Object.assign({},d.ui,s.ui||{});
    s.ui.welcomeConfirmed=!!s.ui.welcomeConfirmed;
    s.ui.oldDataDetected=!!s.ui.oldDataDetected;
    s.ui.lastLogReadAt=Number(s.ui.lastLogReadAt||0)||0;

    s.scan=Object.assign({},d.scan,s.scan||{});
    s.scan.busy=!!s.scan.busy;
    s.scan.paused=!!s.scan.paused;
    s.scan.cancelRequested=!!s.scan.cancelRequested;
    s.scan.scannedL=Math.max(0,Number(s.scan.scannedL||0));
    s.scan.totalL=Math.max(0,Number(s.scan.totalL||0));
    s.scan.lastActive=Number(s.scan.lastActive||0);
    s.scan.busySince=Number(s.scan.busySince||0);

    s.lorebook_meta=Object.assign({},d.lorebook_meta,s.lorebook_meta||{});
    if(!Array.isArray(s.lorebook_meta.deleted_identifiers))s.lorebook_meta.deleted_identifiers=[];
    if(!s.lorebook_meta.entry_hashes||typeof s.lorebook_meta.entry_hashes!=='object')s.lorebook_meta.entry_hashes={};
    if(!s.lorebook_meta.entry_touched||typeof s.lorebook_meta.entry_touched!=='object')s.lorebook_meta.entry_touched={};

    if(!s.import_buffer||typeof s.import_buffer!=='object'){
        s.import_buffer={pending:[],last_import:null};
    }
    if(!Array.isArray(s.import_buffer.pending))s.import_buffer.pending=[];

    if(!s.user_content_type_prefs||typeof s.user_content_type_prefs!=='object')s.user_content_type_prefs={};
    if(!Array.isArray(s.recent_content_type_choices))s.recent_content_type_choices=[];

    s.summaries.forEach(function(x,i){
        x.id=x.id||uid('sum');
        x.title=x.title||'阶段总结';
        x.summary=x.summary||x.content||'';
        x.content=x.content||x.summary||'';
        x.startL=Number(x.startL||x.startA||0)||0;
        x.endL=Number(x.endL||x.endA||0)||0;
        x.round=x.round||i+1;
        x.created_at=x.created_at||now();
        x.updated_at=x.updated_at||x.created_at;
        if(!Array.isArray(x.revisions))x.revisions=[];
        x.deleted=!!x.deleted;
    });

    s.long_term.forEach(function(x,i){
        x.id=x.id||uid('lt');
        x.title=x.title||'长期记忆';
        x.content=x.content||'';
        x.startL=Number(x.startL||x.startA||0)||0;
        x.endL=Number(x.endL||x.endA||0)||0;
        x.round=x.round||i+1;
        x.created_at=x.created_at||now();
        x.updated_at=x.updated_at||x.created_at;
        if(!Array.isArray(x.revisions))x.revisions=[];
        x.deleted=!!x.deleted;
    });

    s.events.forEach(function(e){
        e.id=e.id||uid('ev');
        e.title=e.title||'未命名回忆';
        e.startL=Number(e.startL||e.startA||0)||0;
        e.endL=Number(e.endL||e.endA||e.startL||0)||0;
        e.time_label=e.time_label||'';
        e.weight=Number(e.weight||3)||3;

        if(e.display_form&&!e.content_type){
            var oldMap={monologue:'voice_memo',scene:'voice_memo',capsule:'time_capsule'};
            e.content_type=oldMap[e.display_form]||'voice_memo';
            delete e.display_form;
        }else if(!e.content_type){
            e.content_type='voice_memo';
        }
        if(!['voice_memo','counseling','time_capsule','diary'].includes(e.content_type)){
            e.content_type='voice_memo';
        }

        if(!Array.isArray(e.tags))e.tags=[];
        e.quote=e.quote||'';
        e.outputs=e.outputs&&typeof e.outputs==='object'?e.outputs:{};
        e.created_at=e.created_at||now();
        e.updated_at=e.updated_at||e.created_at;
        if(!Array.isArray(e.revisions))e.revisions=[];
        e.deleted=!!e.deleted;
    });

    s.points.forEach(function(p){
        p.id=p.id||uid('pt');
        p.event_id=p.event_id||'';
        p.type=p.type||'细节';
        p.title=p.title||'记忆点';
        p.quote=p.quote||'';
        p.importance=Number(p.importance||3)||3;
        p.created_at=p.created_at||now();
    });

    s.milestones.forEach(function(m){
        m.id=m.id||uid('ms');
        m.event_id=m.event_id||'';
        m.title=m.title||'未命名时刻';
        m.L=Number(m.L||m.A||0)||0;
        m.month=m.month||'';
        m.importance=Number(m.importance||3)||3;
        m.char_comment=m.char_comment||'';
        if(!Array.isArray(m.dialogue))m.dialogue=[];
        m.created_at=m.created_at||now();
    });

    return s
}

async function rawGet(k){
    var v=null;
    try{v=await T.tavo.get(k,'chat')}catch(_){
        try{v=await T.tavo.get(k)}catch(_2){}
    }
    if(typeof v==='string'){
        try{v=JSON.parse(v)}catch(_3){}
    }
    return v
}

async function rawSet(k,v){
    try{return await T.tavo.set(k,v,'chat')}catch(_){
        try{return await T.tavo.set(k,v)}catch(e){
            console.warn('[Memo save]',e)
        }
    }
}

async function load(){
    var chatId='default';
    try{
        var chat=await T.tavo.chat.current();
        chatId=chat&&chat.id!=null?String(chat.id):'default';
    }catch(_){}

    var newKey=getStoreKey(chatId);
    var s=await rawGet(newKey);
    if(!s||typeof s!=='object')s={};

    if(Object.keys(s).length===0){
        var oldData=await rawGet(STORE);
        if(oldData&&typeof oldData==='object'){
            s=oldData;
            s.boundChatId=chatId;
            await rawSet(newKey,s);
        }
    }

    app.state=normalize(s);

    if(app.state.boundChatId===chatId&&app.state.logs&&!app.state.logs.some(function(l){return l.text==='数据迁移'})){
        app.state.logs.push({
            id:uid('log'),
            time:now(),
            text:'数据迁移',
            status:'ok',
            detail:'从旧存储迁移到新隔离存储'
        });
    }

    if(app.state.scan.busy&&app.state.scan.lastActive&&(now()-app.state.scan.lastActive>600000)){
        app.state.scan.busy=false;
        app.state.scan.type=null;
        app.state.scan.paused=false;
        app.state.logs.push({
            id:uid('log'),
            time:now(),
            text:'任务超时恢复',
            status:'ok',
            detail:'上一个任务因超时自动重置'
        });
    }

    return app.state
}

