function bindBase(){
    var r=ensureRoot();
    if(r.getAttribute('data-base-bound')==='1')return;
    r.setAttribute('data-base-bound','1');

    r.addEventListener('click',function(e){
        var n=e.target.closest?e.target.closest('[data-base-close],[data-overlay-close]'):null;
        if(!n)return;
        e.preventDefault();
        e.stopPropagation();
        if(n.hasAttribute('data-base-close'))close();
        if(n.hasAttribute('data-overlay-close'))closeOverlay()
    },true)
}

async function getAllMessages(){
    try{
        var c=await T.tavo.message.count();
        if(!c)return[];
        var arr=await T.tavo.message.find([0,c-1]);
        return Array.isArray(arr)?arr.filter(Boolean):[]
    }catch(_){return[]}
}

function getAssistantSlots(msgs){
    var out=[];
    msgs=Array.isArray(msgs)?msgs:[];
    for(var i=0;i<msgs.length;i++){
        if(msgs[i]&&msgs[i].role==='assistant'&&!mountMsg(msgs[i])){
            out.push({L:out.length+1,index:i,id:String(msgs[i].id||''),msg:msgs[i]})
        }
    }
    return out
}

async function countAssistant(forceRefresh){
    try{
        var c=await T.tavo.message.count();
        if(!forceRefresh&&app._lastMsgCount===c&&app._assistantCount!=null){
            return app._assistantCount
        }
        app._lastMsgCount=c;
        var msgs=await getAllMessages();
        var slots=getAssistantSlots(msgs);
        app._assistantCount=slots.length;
        app._totalMessages=msgs.length;
        app._allMessages=msgs;

        app._assistantSlotsCache=slots;
        app._allMessagesCache=msgs;
        app._cacheTimestamp=now();

        return slots.length
    }catch(_){return app._assistantCount||0}
}

async function getNames(){
    var o={charName:'角色',userName:'你',charMap:{}};
    try{
        var ch=await T.tavo.chat.current();
        if(ch&&Array.isArray(ch.characters)){
            ch.characters.forEach(function(c){
                if(c&&c.id!=null){
                    o.charMap[c.id]=c.name||'角色';
                    if(o.charName==='角色')o.charName=c.name||'角色'
                }
            })
        }
        if(ch&&ch.persona&&ch.persona.name)o.userName=ch.persona.name
    }catch(_){}
    return o
}

function assistantLAt(slots,idx){
    var n=0;
    for(var i=0;i<slots.length;i++){
        if(slots[i].index<=idx)n=slots[i].L;
        else break
    }
    return n
}

async function collectRange(fromL,toL){
    var msgs,slots;

    if(app._allMessagesCache&&app._assistantSlotsCache&&now()-app._cacheTimestamp<30000){
        msgs=app._allMessagesCache;
        slots=app._assistantSlotsCache;
    }else{
        msgs=await getAllMessages();
        slots=getAssistantSlots(msgs);
        app._allMessagesCache=msgs;
        app._assistantSlotsCache=slots;
        app._cacheTimestamp=now();
    }

    var names=await getNames();

    fromL=Math.max(1,Number(fromL)||1);
    toL=Math.max(fromL,Number(toL)||fromL);

    if(!slots.length||fromL>slots.length){
        return{messages:[],startL:fromL,endL:toL,names:names}
    }

    toL=Math.min(toL,slots.length);
    var start=fromL>1?slots[fromL-2].index+1:0;
    var end=slots[toL-1].index;
    var out=[];

    for(var i=start;i<=end&&i<msgs.length;i++){
        var m=msgs[i];
        if(!m||m.role==='system'||mountMsg(m))continue;
        if(m.role!=='assistant'&&m.role!=='user')continue;

        var l=assistantLAt(slots,i);
        out.push({
            index:i,
            line:i+1,
            L:m.role==='assistant'?l:Math.max(fromL,l+1),
            id:m.id,
            role:m.role,
            speaker:m.role==='user'?names.userName:(names.charMap[m.characterId]||names.charName||'角色'),
            characterId:m.characterId||null,
            content:clip(m.content||'',1600)
        });
    }

    return{
        messages:out,
        startL:fromL,
        endL:toL,
        startIndex:start,
        endIndex:end,
        names:names
    }
}

function endpoint(base){
    base=trim(base);
    while(base&&base.slice(-1)==='/')base=base.slice(0,-1);
    if(!base)return'';
    if(base.toLowerCase().slice(-17)==='/chat/completions')return base;
    if(base.toLowerCase().slice(-3)==='/v1')return base+'/chat/completions';
    return base+'/v1/chat/completions'
}

async function callAPI(prompt,opt){
    opt=opt||{};
    var s=app.state||await load();
    var url=endpoint(s.settings.api_base_url);
    var key=trim(s.settings.api_key);
    var model=trim(s.settings.api_model)||'gpt-4o-mini';

    if(!url||!key)throw new Error('未配置 API');

    var maxRetries=3;
    var retryDelay=1000;
    for(var i=0;i<=maxRetries;i++){
        try{
            var r=await fetch(url,{
                method:'POST',
                headers:{
                    'Content-Type':'application/json',
                    'Authorization':'Bearer '+key
                },
                body:JSON.stringify({
                    model:model,
                    messages:[{role:'user',content:prompt}],
                    temperature:opt.temperature==null?0.25:opt.temperature,
                    max_tokens:opt.max_tokens||2200
                })
            });

            if(!r.ok){
                if((r.status>=500||r.status===429)&&i<maxRetries){
                    await new Promise(function(resolve){setTimeout(resolve,retryDelay*Math.pow(2,i))});
                    continue;
                }
                throw new Error('API 返回 '+r.status);
            }

            var d=await r.json();
            return trim((d.choices&&d.choices[0]&&d.choices[0].message&&d.choices[0].message.content)||'')
        }catch(e){
            if(i===maxRetries)throw e;
            if(e.message&&e.message.indexOf('API 返回')===0)throw e;
            await new Promise(function(resolve){setTimeout(resolve,retryDelay*Math.pow(2,i))});
        }
    }
}

async function generateText(prompt,opt){
    opt=opt||{};
    var s=app.state||await load();

    if(trim(s.settings.api_base_url)&&trim(s.settings.api_key)){
        try{return await callAPI(prompt,opt)}catch(e){
            console.warn('[Memo API fallback]',e)
        }
    }

    if(T.tavo&&T.tavo.generate)return trim(await T.tavo.generate(prompt,{context:false}));
    throw new Error('没有可用生成接口')
}

function parseJSON(text){
    text=trim(text).replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```$/i,'').trim();
    var a=text.indexOf('{'),b=text.lastIndexOf('}');
    if(a>=0&&b>a)text=text.slice(a,b+1);
    return JSON.parse(text)
}

function buildPrompt(baseText,bundle){
    var lines=[trim(baseText||'')];
    lines.push('');
    lines.push('范围：'+bundle.startL+'L-'+bundle.endL+'L');
    bundle.messages.forEach(function(m){
        lines.push('['+m.L+'L｜'+m.speaker+'] '+m.content)
    });
    return lines.join('\n')
}

function summaryPrompt(bundle,s){
    return buildPrompt((s&&s.settings&&s.settings.prompts&&s.settings.prompts.summary)||DEFAULT_PROMPTS.summary,bundle)
}

function eventPrompt(bundle,s){
    return buildPrompt((s&&s.settings&&s.settings.prompts&&s.settings.prompts.event)||DEFAULT_PROMPTS.event,bundle)
}

function longPrompt(list,s){
    var base=(s&&s.settings&&s.settings.prompts&&s.settings.prompts.long_term)||DEFAULT_PROMPTS.long_term;
    var lines=[trim(base),''];
    list.forEach(function(x,i){
        lines.push('【第'+(i+1)+'段｜'+x.startL+'L-'+x.endL+'L】'+(x.title||'阶段总结')+'：'+(x.summary||x.content||''))
    });
    return lines.join('\n')
}

