    lines.push('');
    lines.push('所有事件细节从记忆点取，不编造。只输出日记正文。');
}

    return lines.join('\n')
}

function pushRev(x){
    x.revisions=x.revisions||[];
    x.revisions.push({
        time:now(),
        title:x.title,
        summary:x.summary,
        content:x.content,
        quote:x.quote,
        tags:x.tags,
        content_type:x.content_type,
        weight:x.weight,
        time_label:x.time_label
    });
    if(x.revisions.length>3)x.revisions=x.revisions.slice(-3)
}

function findEventMatch(s,r){
    var rt=sig(r.title);
    for(var i=0;i<s.events.length;i++){
        var e=s.events[i];
        if(e.deleted)continue;
        if(sig(e.title)===rt)return e;
        if(r.quote&&e.quote&&sig(r.quote)===sig(e.quote))return e
    }
    return null
}

function applyEvents(s,data,bundle){
    data=data||{};
    var made=0;
    var events=Array.isArray(data.events)?data.events:[];

    var meaningful=(bundle.messages||[]).filter(function(m){
        return m&&m.content&&!mountMsg(m)&&(m.role==='user'||m.role==='assistant');
    });
    if(meaningful.length<3)return 0;

    events.slice(0,4).forEach(function(r){
        if(!r||!r.title)return;

        var contentType=r.content_type;
        if(!['voice_memo','counseling','time_capsule','diary'].includes(contentType)){
            contentType=recommendContentType({title:r.title,quote:r.quote,weight:r.weight,time_label:r.time_label},Array.isArray(r.points)?r.points:[],s.recent_content_type_choices,s.user_content_type_prefs);
        }

        var raw={
            title:clip(r.title,42),
            startL:Number(r.startL||bundle.startL)||bundle.startL,
            endL:Number(r.endL||bundle.endL)||bundle.endL,
            time_label:clip(r.time_label||'',24),
            weight:Number(r.weight||4)||4,
            content_type:contentType,
            tags:Array.isArray(r.tags)?r.tags.slice(0,5):[],
            quote:clip(r.quote||'',260)
        };

        var ev=findEventMatch(s,raw);
        if(!ev){
            ev={
                id:uid('ev'),
                title:raw.title,
                startL:raw.startL,
                endL:raw.endL,
                time_label:raw.time_label,
                weight:raw.weight,
                content_type:raw.content_type,
                tags:raw.tags,
                quote:raw.quote,
                outputs:{},
                created_at:now(),
                updated_at:now(),
                revisions:[],
                deleted:false
            };
            s.events.push(ev);
            made++
        }else{
            pushRev(ev);
            ev.startL=Math.min(ev.startL||raw.startL,raw.startL);
            ev.endL=Math.max(ev.endL||raw.endL,raw.endL);
            ev.weight=Math.max(ev.weight||3,raw.weight);
            ev.time_label=ev.time_label||raw.time_label;
            ev.quote=ev.quote||raw.quote;
            ev.tags=Array.from(new Set([].concat(ev.tags||[],raw.tags||[]))).slice(0,5);
            ev.updated_at=now()
        }

        var pts=Array.isArray(r.points)?r.points:[];
        pts.slice(0,8).forEach(function(p){
            if(!p||!p.title)return;
            var qt=clip(p.quote||'',260);
            if(qt&&s.points.some(function(x){return x.event_id===ev.id&&sig(x.quote)===sig(qt)}))return;
            s.points.push({
                id:uid('pt'),
                event_id:ev.id,
                type:clip(p.type||'细节',16),
                title:clip(p.title,90),
                quote:qt,
                importance:ev.weight,
                created_at:now()
            })
        });
    });

    var ms=Array.isArray(data.milestones)?data.milestones:[];
    ms.slice(0,6).forEach(function(m){
        if(!m||!m.title)return;
        if(s.milestones.some(function(x){return sig(x.title)===sig(m.title)}))return;
        s.milestones.push({
            id:uid('ms'),
            event_id:m.event_id||'',
            title:clip(m.title,42),
            L:Number(m.L||bundle.endL)||bundle.endL,
            month:clip(m.month||'',12),
            importance:Number(m.importance||4)||4,
            char_comment:clip(m.char_comment||'',500),
            dialogue:Array.isArray(m.dialogue)?m.dialogue.slice(0,8):[],
            created_at:now()
        })
    });

    if(made)addLogToState(s,'甜蜜回忆 · 自动扫描','ok','发现 '+made+' 个新回忆');
    return made
}

function entryBase(identifier,name,content,enabled){
    return{
        identifier:identifier,
        name:name,
        content:content,
        enabled:enabled!==false,
        strategy:'constant',
        keywords:[],
        secondaryKeywords:[],
        secondaryKeywordStrategy:'none',
        scanDepth:2,
        caseSensitive:false,
        matchWholeWord:false,
        injectionPosition:'lorebookBefore',
        injectionDepth:4,
        injectionRole:'system',
        probability:100,
        sticky:0,
        cooldown:0,
        delay:0
    }
}

async function findLbByName(name){
    try{
        var arr=await T.tavo.lorebook.find(name);
        if(Array.isArray(arr)&&arr.length)return arr[0]
    }catch(_){}

    try{
        var all=await T.tavo.lorebook.all();
        if(Array.isArray(all)){
            for(var i=0;i<all.length;i++){
                if(all[i]&&all[i].name===name){
                    return await T.tavo.lorebook.get(all[i].id)
                }
            }
        }
    }catch(_2){}

    return null
}

async function bindLorebookIds(ids){
    try{
        var chat=await T.tavo.chat.current();
        if(!chat)return;
        chat.lorebooks=Array.isArray(chat.lorebooks)?chat.lorebooks:[];
        var changed=false;

        ids.forEach(function(o){
            if(!o||!o.id)return;
            var has=chat.lorebooks.some(function(x){return String(x.id)===String(o.id)});
            if(!has){
                chat.lorebooks.push({id:o.id,name:o.name});
                changed=true
            }
        });

        if(changed)await T.tavo.chat.update(chat)
    }catch(e){
        console.warn('[Memo bind lorebook]',e)
    }
}

async function ensureLorebooks(){
    var s=await load();
    if(!T.tavo||!T.tavo.lorebook)return s;

    var chat=null;
    try{chat=await T.tavo.chat.current()}catch(_){}
    var chatId=chat&&chat.id!=null?String(chat.id):"default";
    var names=await getNames();
    var charName=names.charName||"角色";

        var newInjName="记忆系统 - "+charName+" - 聊天"+chatId+" - 当前注入书";
    var newArcName="记忆系统 - "+charName+" - 聊天"+chatId+" - 档案书";

    // 兼容旧版命名（用于查找和迁移）
    var injNames=[
        newInjName,
        "记忆V6｜"+charName+"｜聊天"+chatId+"｜当前注入书",
        "记忆系统 - 注入"
    ];
    var arcNames=[
        newArcName,
        "记忆V6｜"+charName+"｜聊天"+chatId+"｜档案书",
        "记忆系统 - 归档"
    ];

    if(s.boundChatId&&s.boundChatId!==chatId){
        s.lorebook_meta.inject_id=null;
        s.lorebook_meta.archive_id=null
    }
    s.boundChatId=chatId;

    var inj=null;
    if(s.lorebook_meta.inject_id){
        try{inj=await T.tavo.lorebook.get(s.lorebook_meta.inject_id)}catch(_){}
    }
    if(!inj){
        for(var i=0;i<injNames.length;i++){
            inj=await findLbByName(injNames[i]);
            if(inj)break;
        }
    }

    var arc=null;
    if(s.lorebook_meta.archive_id){
        try{arc=await T.tavo.lorebook.get(s.lorebook_meta.archive_id)}catch(_){}
    }
    if(!arc){
        for(var j=0;j<arcNames.length;j++){
            arc=await findLbByName(arcNames[j]);
            if(arc)break;
        }
    }

        // 验证找到的书是否绑定在当前聊天
    if(inj){
        var chatInj=chat.lorebooks&&chat.lorebooks.some(function(lb){return String(lb.id)===String(inj.id)});
        if(!chatInj){
            // 未绑定到当前聊天，视为无效
            inj=null;
            s.lorebook_meta.inject_id=null;
        }
    }

    if(!inj){
        var injId=await T.tavo.lorebook.create({
            name:newInjName,
            entries:[entryBase("memo_root","记忆系统注入","【长期记忆与近期总结将在此处自动更新】",true)]
        });
        inj=await T.tavo.lorebook.get(injId);
        addLogToState(s,"世界书","ok","已创建注入世界书："+newInjName)
    }else{
        var oldInjName=inj.name;
        if(oldInjName!==newInjName){
            inj.name=newInjName;
            await T.tavo.lorebook.update(inj);
            addLogToState(s,"世界书","ok","已将注入书从 \""+oldInjName+"\" 重命名为 \""+newInjName+"\"");
        }
    }

        // 验证找到的书是否绑定在当前聊天
    if(arc){
        var chatArc=chat.lorebooks&&chat.lorebooks.some(function(lb){return String(lb.id)===String(arc.id)});
        if(!chatArc){
            arc=null;
            s.lorebook_meta.archive_id=null;
        }
    }

    if(!arc){
        var arcId=await T.tavo.lorebook.create({
            name:newArcName,
            entries:[entryBase("memo_archive_root","记忆归档","【历史总结归档将在此处自动存储】",false)]
        });
        arc=await T.tavo.lorebook.get(arcId);
        addLogToState(s,"世界书","ok","已创建归档世界书："+newArcName)
    }else{
        var oldArcName=arc.name;
        if(oldArcName!==newArcName){
            arc.name=newArcName;
            await T.tavo.lorebook.update(arc);
            addLogToState(s,"世界书","ok","已将档案书从 \""+oldArcName+"\" 重命名为 \""+newArcName+"\"");
        }
    }

    s.lorebook_meta.inject_id=inj&&inj.id;
    s.lorebook_meta.archive_id=arc&&arc.id;

        await bindLorebookIds([
        {id:s.lorebook_meta.inject_id,name:newInjName},
        {id:s.lorebook_meta.archive_id,name:newArcName}
    ]);

    await save(s);
    return s
}

