async function syncOneLorebook(lb,desired,s,opt){
    if(!lb)return;
    opt=opt||{};
    lb.entries=Array.isArray(lb.entries)?lb.entries:[];

    var by={};
    lb.entries.forEach(function(e){
        if(e&&e.identifier)by[e.identifier]=e
    });

    var desiredIds={};
    desired.forEach(function(e){desiredIds[e.identifier]=true});

    lb.entries.forEach(function(e){
        if(e&&e.identifier&&/^memo_/.test(e.identifier)&&!desiredIds[e.identifier]){
            if(s.lorebook_meta.deleted_identifiers.indexOf(e.identifier)<0){
                s.lorebook_meta.deleted_identifiers.push(e.identifier)
            }
        }
    });

    var keep=lb.entries.filter(function(e){
        return !(e&&e.identifier&&/^memo_/.test(e.identifier)&&!desiredIds[e.identifier])
    });

    desired.forEach(function(ne){
        if(s.lorebook_meta.deleted_identifiers.indexOf(ne.identifier)>=0&&opt.reason!=='rebuild')return;

        var old=by[ne.identifier];
        var newHash=hashText(ne.content);

        if(old){
            var oldHash=hashText(old.content||'');
            var last=s.lorebook_meta.entry_hashes[ne.identifier];
            var userChanged=last&&oldHash!==last;

            if(userChanged&&opt.reason!=='edit'&&opt.reason!=='reroll'&&opt.reason!=='rebuild'){
                return
            }

            Object.assign(old,ne);
            s.lorebook_meta.entry_hashes[ne.identifier]=newHash;
            if(keep.indexOf(old)<0)keep.push(old);
        }else{
            keep.push(ne);
            s.lorebook_meta.entry_hashes[ne.identifier]=newHash;
        }
    });

    lb.entries=keep;
    await T.tavo.lorebook.update(lb);
}

async function syncLorebooks(opt){
    opt=opt||{reason:'auto'};
    var s=await ensureLorebooks();
    if(!T.tavo||!T.tavo.lorebook)return s;

    if(opt.reason==='rebuild'){
        s.lorebook_meta.deleted_identifiers=[]
    }

    var inj=s.lorebook_meta.inject_id?await T.tavo.lorebook.get(s.lorebook_meta.inject_id):null;
    var arc=s.lorebook_meta.archive_id?await T.tavo.lorebook.get(s.lorebook_meta.archive_id):null;

    await syncOneLorebook(inj,desiredEntries(s,false),s,opt);
    await syncOneLorebook(arc,desiredEntries(s,true),s,opt);

    addLogToState(s,'世界书同步','ok',opt.reason||'auto');
    await save(s);
    return s
}

