async function runSummary(){
    var s=await load();
    var cur=await countAssistant();

    if(!s.started){
        toast('请先点击从下一条回复开始');
        return null
    }

    if(s.scan.busy){
        toast('记忆整理正在运行');
        return null
    }

    var fromL=s.processedL+1;
    var toL=Math.min(cur,s.processedL+(s.settings.interval||24));

    if(fromL>cur){
        toast('没有新的 AI 回复');
        return null
    }

    s.scan.busy=true;
    s.scan.type='summary';
    s.scan.busySince=now();
    s.scan.lastActive=now();
    addLogToState(s,'短期总结 · 第 '+(s.summaries.filter(function(x){return !x.deleted}).length+1)+' 轮','running',fromL+'L-'+toL+'L · 正在生成总结…');
    await save(s);
    if(app.ui&&app.ui.renderAll)app.ui.renderAll();

    try{
        var bundle=await collectRange(fromL,toL);
        if(!bundle.messages.length)throw new Error('无可整理消息');

        var stxt=await generateText(summaryPrompt(bundle,s),{max_tokens:1600,temperature:0.25});
        var sd;
        try{sd=parseJSON(stxt)}catch(_){sd={title:'阶段总结',summary:stxt}}

        var item={
            id:uid('sum'),
            title:clip(sd.title||('阶段总结 '+fromL+'L-'+toL+'L'),42),
            summary:trim(sd.summary||stxt),
            content:trim((sd.title?sd.title+'\n':'')+(sd.summary||stxt)),
            startL:fromL,
            endL:toL,
            created_at:now(),
            updated_at:now(),
            round:s.summaries.length+1,
            revisions:[],
            deleted:false
        };

        s.summaries.push(item);
        s.processedL=toL;

        addLogToState(s,'短期总结 · 第 '+item.round+' 轮','ok',fromL+'L-'+toL+'L · 已完成');

        var rounds=s.settings.long_term_rounds||4;
        var active=s.summaries.filter(function(x){return !x.deleted});

        if(active.length&&active.length%rounds===0){
            var use=active.slice(-rounds);
            var ltxt=await generateText(longPrompt(use,s),{max_tokens:2000,temperature:0.25});
            var ld;
            try{ld=parseJSON(ltxt)}catch(_2){ld={title:'长期记忆',content:ltxt}}

            s.long_term.push({
                id:uid('lt'),
                title:clip(ld.title||'长期记忆',42),
                content:trim(ld.content||ltxt),
                startL:use[0].startL,
                endL:use[use.length-1].endL,
                created_at:now(),
                updated_at:now(),
                round:s.long_term.length+1,
                revisions:[],
                deleted:false
            });

            addLogToState(s,'长期记忆升级','ok','基于 '+rounds+' 次短期总结更新整体画像');
        }

        s.scan.busy=false;
        s.scan.type=null;
        await save(s);

        try{await syncLorebooks({reason:'auto'})}catch(_3){}

        toast('整理完成');
        if(app.ui&&app.ui.renderAll)app.ui.renderAll();
        return item

    }catch(e){
        s.scan.busy=false;
        s.scan.type=null;
        addLogToState(s,'短期总结失败','err',clip(e.message||'未知错误',80));
        await save(s);
        toast('整理失败：'+clip(e.message||'未知错误',50));
        if(app.ui&&app.ui.renderAll)app.ui.renderAll();
        return null
    }
}

async function scanEvents(){
    var s=await load();
    var cur=await countAssistant();

    if(!s.started){
        toast('请先点击从下一条回复开始');
        return null
    }

        if(cur<10){
        return null
    }

    if(s.scan.busy){
        toast('记忆整理正在运行');
        return null
    }

    var fromL=s.scan.scannedL+1;
    var toL=cur;

    if(fromL>toL){
        toast('没有新的内容可扫描');
        return null
    }

    s.scan.busy=true;
    s.scan.type='event_scan';
    s.scan.totalL=toL;
    s.scan.paused=false;
    s.scan.cancelRequested=false;
    s.scan.busySince=now();
    s.scan.lastActive=now();
    addLogToState(s,'甜蜜回忆扫描','running','开始扫描 '+fromL+'L-'+toL+'L');
    await save(s);
    if(app.ui&&app.ui.renderAll)app.ui.renderAll();

    var chunkSize=25;
    var cursor=fromL;
    var totalFound=0;

    try{
        while(cursor<=toL){
            if(s.scan.cancelRequested){
                addLogToState(s,'甜蜜回忆扫描','ok','用户取消，已扫描到 '+cursor+'L');
                break;
            }
            if(s.scan.paused){
                addLogToState(s,'甜蜜回忆扫描','ok','用户暂停，已扫描到 '+cursor+'L');
                break;
            }

            var chunkEnd=Math.min(cursor+chunkSize-1,toL);
            var bundle=await collectRange(cursor,chunkEnd);

            if(bundle.messages.length){
                var etxt=await generateText(eventPrompt(bundle,s),{max_tokens:2600,temperature:0.25});
                var data;
                try{data=parseJSON(etxt)}catch(_){data={events:[]}}

                var found=applyEvents(s,data,bundle);
                totalFound+=found;
            }

            s.scan.scannedL=chunkEnd;
            cursor=chunkEnd+1;
            s.scan.lastActive=now();

            await save(s);
            if(app.ui&&app.ui.renderAll)app.ui.renderAll();
        }

        s.scan.busy=false;
        s.scan.type=null;
        if(s.scan.scannedL>=toL){
            addLogToState(s,'甜蜜回忆扫描完成','ok','共发现 '+totalFound+' 个事件');
        }
        await save(s);

        try{await syncLorebooks({reason:'scan-events'})}catch(_3){}

        toast(totalFound?('扫描完成，发现 '+totalFound+' 个事件'):'扫描完成，没有发现新事件');
        if(app.ui&&app.ui.renderAll)app.ui.renderAll();
        return totalFound

    }catch(e){
        s.scan.busy=false;
        s.scan.type=null;
        addLogToState(s,'甜蜜回忆扫描失败','err',clip(e.message||'未知错误',80));
        await save(s);
        toast('扫描失败：'+clip(e.message||'未知错误',50));
        if(app.ui&&app.ui.renderAll)app.ui.renderAll();
        return null
    }
}

