async function rerollEvent(id){
    var s=await load();
    var ev=s.events.find(function(v){return v.id===id});
    if(!ev||ev.deleted){
        toast('找不到甜蜜回忆');
        return
    }

    var bundle=await collectRange(ev.startL,ev.endL);
    if(!bundle.messages.length){
        toast('无可重抽消息');
        return
    }

    pushRev(ev);
    toast('正在重抽甜蜜回忆...');

    var txt=await generateText(eventPrompt(bundle,s),{max_tokens:2600,temperature:0.35});
    var data=parseJSON(txt);
    var r=data&&Array.isArray(data.events)&&data.events[0];
    if(!r)throw new Error('没有生成回忆事件');

    ev.title=clip(r.title||ev.title,42);
    ev.startL=Number(r.startL||ev.startL)||ev.startL;
    ev.endL=Number(r.endL||ev.endL)||ev.endL;
    ev.time_label=clip(r.time_label||'',24);
    ev.weight=Number(r.weight||ev.weight)||ev.weight;

    if(r.content_type&&['voice_memo','counseling','time_capsule','diary'].includes(r.content_type)){
        ev.content_type=r.content_type;
    }

    ev.tags=Array.isArray(r.tags)?r.tags.slice(0,5):[];
    ev.quote=clip(r.quote||'',260);
    ev.outputs={};
    ev.updated_at=now();

    s.points=s.points.filter(function(p){return p.event_id!==id});

    safeArr(r.points).slice(0,8).forEach(function(p){
        if(!p||!p.title)return;
        s.points.push({
            id:uid('pt'),
            event_id:id,
            type:clip(p.type||'细节',16),
            title:clip(p.title,90),
            quote:clip(p.quote||'',260),
            importance:ev.weight,
            created_at:now()
        })
    });

    addLogToState(s,'甜蜜回忆已重抽','ok',ev.title);
    await save(s);

    try{await syncLorebooks({reason:'reroll'})}catch(_2){}
    if(app.ui&&app.ui.renderAll)app.ui.renderAll();
    toast('重抽完成')
}

async function updateEvent(id,patch,points){
    var s=await load();
    var ev=s.events.find(function(v){return v.id===id});
    if(!ev)return;

    pushRev(ev);
    patch=patch||{};

    if(patch.title!=null)ev.title=clip(patch.title,42);
    if(patch.time_label!=null)ev.time_label=clip(patch.time_label,24);
    if(patch.weight!=null)ev.weight=Number(patch.weight)||ev.weight;
    if(patch.content_type!=null&&['voice_memo','counseling','time_capsule','diary'].includes(patch.content_type)){
        ev.content_type=patch.content_type;
        if(!s.user_content_type_prefs[patch.content_type]){
            s.user_content_type_prefs[patch.content_type]={count:0,lastUsed:0};
        }
        s.user_content_type_prefs[patch.content_type].count++;
        s.user_content_type_prefs[patch.content_type].lastUsed=now();
        s.recent_content_type_choices.push({type:patch.content_type,manual:true,time:now()});
        if(s.recent_content_type_choices.length>10)s.recent_content_type_choices=s.recent_content_type_choices.slice(-10);
    }
    if(patch.tags!=null){
        ev.tags=Array.isArray(patch.tags)?patch.tags:String(patch.tags).split(/[,，、\s]+/).filter(Boolean).slice(0,5)
    }
    if(patch.quote!=null)ev.quote=clip(patch.quote,260);

    ev.outputs={};
    ev.updated_at=now();
    ev.deleted=false;

    if(Array.isArray(points)){
        s.points=s.points.filter(function(p){return p.event_id!==id});
        points.slice(0,12).forEach(function(p){
            if(!p||!p.title)return;
            s.points.push({
                id:p.id||uid('pt'),
                event_id:id,
                type:clip(p.type||'细节',16),
                title:clip(p.title,90),
                quote:clip(p.quote||'',260),
                importance:ev.weight,
                created_at:p.created_at||now()
            })
        })
    }

    addLogToState(s,'甜蜜回忆已编辑','ok',ev.title);
    await save(s);

    try{await syncLorebooks({reason:'edit'})}catch(_){}
    if(app.ui&&app.ui.renderAll)app.ui.renderAll();
    toast('已保存')
}

