async function generateOutput(eventId,type){
    type=type||'voice_memo';
    var s=await load();
    var ev=s.events.find(function(x){return x.id===eventId&&!x.deleted});
    if(!ev)return null;

    ev.outputs=ev.outputs||{};
    if(ev.outputs[type])return ev.outputs[type];

    var pts=s.points.filter(function(p){return p.event_id===eventId}).map(function(p){
        return{type:p.type,title:p.title,quote:p.quote}
    });

    addLogToState(s,'甜蜜回忆展示生成 · '+type,'running','「'+ev.title+'」');
    await save(s);
    if(app.ui&&app.ui.renderAll)app.ui.renderAll();

    try{
        var txt=await generateText(outputPrompt(ev,pts,type),{max_tokens:3200,temperature:0.5});
        ev.outputs[type]=trim(txt);
        ev.updated_at=now();

        addLogToState(s,'甜蜜回忆展示生成','ok','「'+ev.title+'」');
        await save(s);
        if(app.ui&&app.ui.renderAll)app.ui.renderAll();
        return ev.outputs[type]

    }catch(e){
        addLogToState(s,'甜蜜回忆展示生成失败','err',clip(e.message||'未知错误',80));
        await save(s);
        toast('生成失败：'+clip(e.message||'未知错误',50));
        if(app.ui&&app.ui.renderAll)app.ui.renderAll();
        return null
    }
}

